import frappe

@frappe.whitelist()
def delivery_trip_optimize_route(delivery_trip):
    """Optimize route for a Delivery Trip using OSRM"""
    if not delivery_trip:
        frappe.throw('Delivery Trip name is required')

    # Check document exists
    if not frappe.db.exists('Delivery Trip', delivery_trip):
        frappe.throw(f'Delivery Trip {delivery_trip} not found')

    # Call the existing OSRM route optimizer
    result = frappe.call(
        'route_optimizer.api.delivery_trip.optimize_route_osrm',
        delivery_trip=delivery_trip
    )

    frappe.db.commit()

    return {
        'status': 'success',
        'message': f'Route optimized successfully for {delivery_trip}',
        'result': result
    }

