# Server Script: Staffing Plan, Event: Validate

import frappe

def get_current_count(sp_doc, d):
    """
    Count active employees based on designation + company + department.
    """
    return frappe.db.count(
        "Employee",
        filters={
            "designation": d.designation,
            "company": sp_doc.company,
            "department": sp_doc.department,
            "status": "Active"
        }
    )

# Update current_count for all children
for d in doc.staffing_details:
    d.current_count = get_current_count(doc, d)

def create_source_stock_entry(doc):
    frappe.msgprint("create_source_stock_entry called")
    try:
        se = frappe.get_doc({
            "doctype": "Stock Entry",
            "stock_entry_type": "Warehouse Transfer",
            "company": doc.source_company,
            "posting_date": doc.date_transferred or nowdate(),
            "posting_time": now(),
            "from_warehouse": doc.source_warehouse,
            "items": []
        })
        for item in doc.transfer_items:
            frappe.msgprint(f"Adding item to source stock entry: {item.item_code}, qty: {item.issued_qty}")
            se.append("items", {
                "item_code": item.item_code,
                "qty": item.issued_qty,
                "s_warehouse": doc.source_warehouse
            })
        se.insert(ignore_permissions=True)
        se.submit()
        frappe.msgprint("Source Stock Entry created and submitted")
    except Exception as e:
        frappe.log_error(f"Error creating source Stock Entry: {e}", "Intercompany Transfer Error")
        frappe.throw(f"Error creating source Stock Entry: {e}")

def create_target_stock_entry(doc):
    frappe.msgprint("create_target_stock_entry called")
    try:
        se = frappe.get_doc({
            "doctype": "Stock Entry",
            "stock_entry_type": "Warehouse Transfer Receipt",
            "company": doc.target_company,
            "posting_date": doc.date_received or nowdate(),
            "posting_time": now(),
            "to_warehouse": doc.target_warehouse,
            "items": []
        })
        for item in doc.transfer_items:
            frappe.msgprint(f"Adding item to target stock entry: {item.item_code}, qty: {item.received_qty}")
            se.append("items", {
                "item_code": item.item_code,
                "qty": item.received_qty,
                "t_warehouse": doc.target_warehouse
            })
        se.insert(ignore_permissions=True)
        se.submit()
        frappe.msgprint("Target Stock Entry created and submitted")
    except Exception as e:
        frappe.log_error(f"Error creating target Stock Entry: {e}", "Intercompany Transfer Error")
        frappe.throw(f"Error creating target Stock Entry: {e}")

def create_intercompany_je(doc, source=True):
    frappe.msgprint(f"create_intercompany_je called, source={source}")
    mapping = frappe.get_value(
        "Intercompany Expense Mapping",
        {"source_company": doc.source_company, "target_company": doc.target_company},
        ["source_account", "target_account"],
        as_dict=True
    )
    if not mapping:
        frappe.throw("No Intercompany Expense Mapping found for this transfer.")

    je = frappe.get_doc({
        "doctype": "Journal Entry",
        "posting_date": now(),
        "company": doc.source_company if source else doc.target_company,
        "voucher_type": "Inter Company Journal Entry",
        "accounts": []
    })

    total_amount = 0

    # Compute amount per item using latest Stock Ledger Entry valuation_rate
    for item in doc.transfer_items:
        warehouse = doc.source_warehouse if source else doc.target_warehouse
        company = doc.source_company if source else doc.target_company
        qty = item.issued_qty if source else item.received_qty

        sle = frappe.db.sql("""
            SELECT valuation_rate 
            FROM `tabStock Ledger Entry`
            WHERE item_code = %s AND company = %s AND warehouse = %s
            ORDER BY posting_date DESC, posting_time DESC, creation DESC
            LIMIT 1
        """, (item.item_code, company, warehouse), as_dict=True)

        rate = sle[0].valuation_rate if sle else 0
        line_amount = qty * rate
        total_amount += line_amount

        frappe.msgprint(f"Item {item.item_code}: qty {qty}, rate {rate}, amount {line_amount}")

    frappe.msgprint(f"Total amount for JE: {total_amount}")


    if source:
        je.append("accounts", {
            "account": mapping.source_account,
            "credit_in_account_currency": total_amount
        })
        je.append("accounts", {
            "account": mapping.target_account,
            "debit_in_account_currency": total_amount
        })
    else:
        je.append("accounts", {
            "account": mapping.target_account,
            "credit_in_account_currency": total_amount
        })
        je.append("accounts", {
            "account": mapping.source_account,
            "debit_in_account_currency": total_amount
        })

    je.insert(ignore_permissions=True)
    je.submit()
    frappe.msgprint("Intercompany Journal Entry created and submitted")

def after_submit(doc, method):
    frappe.msgprint("✅ on_submit triggered")
    if doc.transfer_status == "Transferred":
        frappe.msgprint("Workflow state: Transferred")
        create_source_stock_entry(doc)
        if doc.source_company != doc.target_company:
            create_intercompany_je(doc, source=True)

    elif doc.transfer_status == "Received":
        frappe.msgprint("Workflow state: Received")
        create_target_stock_entry(doc)
        if doc.source_company != doc.target_company:
            create_intercompany_je(doc, source=False)

if not doc.custom_additional_manpower:
    vacancies = int(doc.custom_vacancies or 0)
    positions = int(doc.no_of_positions or 0)

    if positions > vacancies:
        frappe.throw(
            f"Number of Positions ({positions}) cannot be greater than available Vacancies ({vacancies})."
        )

if doc.no_of_positions and len(doc.custom_employees) > doc.no_of_positions:
    frappe.throw(
        f"You can only add {doc.no_of_positions} employee(s)."
    )

for row in doc.assets:
    asset = frappe.get_doc("Asset", row.asset)

    if not asset.custodian:
        asset.db_set("custom_custodian_name", "")
        asset.db_set("department", "")
    else:
        employee = frappe.db.get_value(
            "Employee",
            asset.custodian,
            ["employee_name", "custom_location", "department"],
            as_dict=True
        )

        if employee:
            asset.db_set("custom_custodian_name", employee.employee_name)
            asset.db_set("location", employee.custom_location)
            asset.db_set("department", employee.department)
